            d_me = cheb(sx, sy, rx, ry)
            d_op = cheb(ox, oy, rx, ry)
            behind = d_me - d_op  # smaller is better; >0 means opponent closer
            tup = (behind, d_me, rx, ry)
            if best is None or tup < best[0]:
                best = (tup, (rx, ry))
        tx, ty = best[1]

    best_move = None
    best_score = None
    for dx, dy in legal:
        nx, ny = sx + dx, sy + dy
        d_me = cheb(nx, ny, tx, ty)
        d_op_next = cheb(nx, ny, ox, oy)
        # Score: prioritize reducing distance to target; secondarily keep away from opponent
        score = (d_me, -d_op_next, (nx - tx) * (nx - tx) + (ny - ty) * (ny - ty), dx, dy)
        if best_score is None or score < best_score:
            best_score = score
            best_move = (dx, dy)
    return [int(best_move[0]), int(best_move[1])]
